/**
 * @summary List recent attempts for an exam
 */
export const getListAttemptsForExamUrl = (
  examId: string,
  params?: ListAttemptsForExamParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/exams/${examId}/attempts?${stringifiedParams}`
    : `/api/exams/${examId}/attempts`;
};

export const listAttemptsForExam = async (
  examId: string,
  params?: ListAttemptsForExamParams,
  options?: RequestInit,
): Promise<AttemptSummary[]> => {
  return customFetch<AttemptSummary[]>(
    getListAttemptsForExamUrl(examId, params),
    {
      ...options,
      method: "GET",
    },
  );
};

export const getListAttemptsForExamQueryKey = (
  examId: string,
  params?: ListAttemptsForExamParams,
) => {
  return [
    `/api/exams/${examId}/attempts`,
    ...(params ? [params] : []),
  ] as const;
};

export const getListAttemptsForExamQueryOptions = <
  TData = Awaited<ReturnType<typeof listAttemptsForExam>>,
  TError = ErrorType<unknown>,
>(
  examId: string,
  params?: ListAttemptsForExamParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof listAttemptsForExam>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey =
    queryOptions?.queryKey ?? getListAttemptsForExamQueryKey(examId, params);

  const queryFn: QueryFunction<
    Awaited<ReturnType<typeof listAttemptsForExam>>
  > = ({ signal }) =>
    listAttemptsForExam(examId, params, { signal, ...requestOptions });

  return {
    queryKey,
    queryFn,
    enabled: !!examId,
    ...queryOptions,
  } as UseQueryOptions<
    Awaited<ReturnType<typeof listAttemptsForExam>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type ListAttemptsForExamQueryResult = NonNullable<
  Awaited<ReturnType<typeof listAttemptsForExam>>
>;
export type ListAttemptsForExamQueryError = ErrorType<unknown>;

/**
 * @summary List recent attempts for an exam
 */

export function useListAttemptsForExam<
  TData = Awaited<ReturnType<typeof listAttemptsForExam>>,
  TError = ErrorType<unknown>,
>(
  examId: string,
  params?: ListAttemptsForExamParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof listAttemptsForExam>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getListAttemptsForExamQueryOptions(
    examId,
    params,
    options,
  );

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}

